import React from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import axios from 'axios';

const StudyRoom = () => {
    const { id } = useParams(); // Task ID from URL
    const navigate = useNavigate();

    const finishDay = async (isCompleted) => {
        try {
            const status = isCompleted ? 'completed' : 'missed';
            
            // API call to update status and trigger rescheduling logic
            await axios.patch(`/api/tasks/${id}`, { status }, {
                headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
            });

            // Redirect back to planPage
            navigate('/planPage');
        } catch (error) {
            console.error("Failed to finish day:", error);
        }
    };

    return (
        <div className="study-room">
            <h2>Current Task</h2>
            <button onClick={() => finishDay(true)}>Finish Day 1 (Completed)</button>
            <button onClick={() => finishDay(false)}>Not Completed (Reschedule)</button>
        </div>
    );
};

export default StudyRoom;
